SELECT count(*) FROM cast_info, char_name, role_type, name, title, aka_name, movie_info, info_type, movie_companies WHERE cast_info.person_role_id = char_name.id AND cast_info.role_id = role_type.id AND cast_info.person_id = name.id AND cast_info.movie_id = title.id AND aka_name.person_id = name.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND movie_companies.movie_id = title.id;